-- ═══════════════════════════════════════════════════════════════════════════
-- TrueSouth FMS — Legacy FlightTable import into ts_flight_records
-- Run in the Supabase SQL editor. SAFE TO RE-RUN (ON CONFLICT DO NOTHING; ids are
-- deterministic 'fr_imp_<legacyID>'). Wrapped in a transaction.
--
--   • Current crew  -> matched to their ts_users account BY NAME (history shows in
--                      their personal logbook). If a name doesn't match, the row
--                      still imports under a placeholder (nothing is lost).
--   • Ex-staff      -> placeholder user_id 'hist_<CODE>' + pic_name kept.
--   • Pilots remapped per era: pre-2025 DO = James Rea; pre-2025 JC = Former JC;
--                      MS <=2020 = Michael Sims, 2021–May2025 = Henry Phelps,
--                      Jun2025+ = Michael Stott.
--   • POB kept as recorded (infants included, per ops/reporting).
--   • actype left blank for retired tails (FIG/JMG/KMH/SLW/SLP) — fill if needed.
--   • details = route summary (e.g. QN-MF-QN); note keeps the original entry.
-- ═══════════════════════════════════════════════════════════════════════════
begin;
create temp table _fr_imp(
  id text, pic text, is_cur boolean, placeholder text, fr_date date, aircraft text, actype text,
  product text, route_from text, route_to text, pob int, off_blocks text, on_blocks text,
  start_hours numeric, end_hours numeric, flight_time numeric, landings int, details text, note text
) on commit drop;






















  start_hours,end_hours,flight_time,tacho,landings,starts,done,submitted,manual,pic_name,details,note)
select i.id,
   coalesce(case when i.is_cur then (select u.id from ts_users u where u.name=i.pic limit 1) end, i.placeholder),
   i.fr_date,i.aircraft,i.product,i.route_from,i.route_to,i.pob,i.off_blocks,i.on_blocks,i.actype,
   i.start_hours,i.end_hours,i.flight_time,i.flight_time,coalesce(i.landings,1),1,true,true,true,i.pic,i.details,i.note
from _fr_imp i
on conflict (id) do nothing;

select count(*) as imported_rows from ts_flight_records where id like 'fr_imp_%';
commit;
